export interface CandidateResult {
  candidateId: string;
  votes: number;
}

export interface Candidate {
  id: string;
  name: string;
  party: string;
  partyColor: string;
  photo?: string;
}

export interface PollingStation {
  id: string;
  name: string;
  registeredVoters: number;
  totalVotes?: number;
  totalRejected?: number;
  candidateResults?: CandidateResult[];
}

export interface Ward {
  id: string;
  name: string;
  pollingStations: PollingStation[];
  councillorCandidates?: Candidate[];
}

export interface Constituency {
  id: string;
  name: string;
  wards: Ward[];
  mpCandidates?: Candidate[];
}

export interface District {
  id: string;
  name: string;
  constituencies: Constituency[];
  mayoralCandidates?: Candidate[];
}

export interface Province {
  id: string;
  name: string;
  districts: District[];
}


export function calculateTurnout(registered: number, votes: number): number {
  if (!registered || registered === 0) return 0;
  return Math.min(100, (votes / registered) * 100);
}

