export function getAllPollingStations(): PollingStation[] {
  const all: PollingStation[] = [];
  for (const p of provinces) {
    for (const d of p.districts) {
      for (const c of d.constituencies) {
        for (const w of c.wards) {
          for (const s of w.pollingStations) {
            all.push(s);
          }
        }
      }
    }
  }
  return all;
}

export function getTotalRegisteredVoters(): number {
  let total = 0;
  for (const p of provinces) {
    for (const d of p.districts) {
      for (const c of d.constituencies) {
        for (const w of c.wards) {
          for (const s of w.pollingStations) {
            total += s.registeredVoters;
          }
        }
      }
    }
  }
  return total;
}

export function getTotalVotesCast(): number {
  let total = 0;
  for (const p of provinces) {
    for (const d of p.districts) {
      for (const c of d.constituencies) {
        for (const w of c.wards) {
          for (const s of w.pollingStations) {
            total += s.totalVotes ?? 0;
          }
        }
      }
    }
  }
  return total;
}

export function getTotalRejectedBallots(): number {
  let total = 0;
  for (const p of provinces) {
    for (const d of p.districts) {
      for (const c of d.constituencies) {
        for (const w of c.wards) {
          for (const s of w.pollingStations) {
            total += s.totalRejected ?? 0;
          }
        }
      }
    }
  }
  return total;
}

export function aggregateResults(stations: PollingStation[]): Map<string, number> {
  const totals = new Map<string, number>();
  for (const s of stations) {
    for (const r of (s.candidateResults ?? [])) {
      totals.set(r.candidateId, (totals.get(r.candidateId) ?? 0) + r.votes);
    }
  }
  return totals;
}


